var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"하하하하하하하핫!! 겨우 이 정도냐, 바퀴벌레!","JPN":"ハーッハハハハハハハッ！！　しょせんはこんなものか、ゴキブリ！","ENG":"Mwa hah hah hah! Is that all you've got, Roach?","TWN":"哈哈哈哈哈哈！！就只有這種程度嗎，蟑螂！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"대원들을 거느리고 으스대 봤자 내 힘에 비하면 하찮기 짝이 없군!","JPN":"ご自慢の戦隊員たちの力も私一人の力に遠く及ばぬではないか！","ENG":"You're nothing compared to my might, even with your entire army!","TWN":"洋洋得意地率領著妳的隊員，結果在我的力量面前根本微不足道！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하아...... 하아......","JPN":"はぁ……はぁ……","ENG":"Huff... Huff...","TWN":"哈啊……哈啊……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 괜찮으십니까?","JPN":"副戦隊長殿、耐えられそうですか？","ENG":"Deputy Commander, are you okay?","TWN":"副隊長，妳沒事吧？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"별로 안 괜찮아...... 침식 증후군이란 게 제법 독하긴 하네.","JPN":"何とか耐えてるけど……侵食症候群ってヤツ、なかなかきついわね。","ENG":"Not really... This Corruption syndrome's really kicking my butt.","TWN":"不怎麼好……這侵蝕症候群確實不好受。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래도, 류드밀라가 애쓰고 있는데 힘든 척 할 수는 없지.","JPN":"でも、リュドミラちゃんが踏ん張ってるときに辛い顔は見せられないわ。","ENG":"But still, I can't let it show when Lyudmila's fighting so hard for us.","TWN":"但是，盧德米拉她正在奮鬥，我可不想在她面前裝出痛苦的模樣。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그렇지 않니, 얘들아?","JPN":"みんなもそう思うわよね？","ENG":"Ain't that right, kids?","TWN":"是吧，隊員們？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그럼요. 제일 힘든 건 언제나 전대장님이었으니까요.","JPN":"もちろんです。一番辛い役を引き受けてくださるのは、\\nいつも戦隊長殿でしたからね。","ENG":"Of course. She always bore the brunt of it all.","TWN":"當然，最辛苦的總是隊長。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"평범한 공격은 통하지 않아......","JPN":"並の攻撃は通じない……","ENG":"Ordinary attacks won't work...","TWN":"普通的攻擊沒有效……"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대원들 상태를 생각하면 시간이 없어......! 대체 어떻게 해야......!","JPN":"隊員たちの状態を考えれば、残り時間はわずか……！\\nいったいどうすれば……！","ENG":"I have to hurry... My troops are running out of time! But how?","TWN":"再考慮到隊員們的狀況……沒有時間了！到底該怎麼辦……！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그거 아나? 난 처음부터 네가 마음에 안 들었어!","JPN":"知っていたか？　私ははじめから貴様のことが気に食わなかったのだ！","ENG":"You know what? I never liked you from the beginning!","TWN":"妳知道嗎？我從一開始就很討厭妳！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그 시건방진 눈초리! 잘난 척 지껄이는 소리들 하며!","JPN":"その挑むような目つき！　いつも偉そうに講釈なんか垂れおって！","ENG":"Those cocky eyes of yours! And all your conceited speech!","TWN":"妳那囂張的眼神！自以為了不起的發言！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"뭐가 원본이고 전대장이야!","JPN":"何がオリジナルだ！　何が戦隊長だ！","ENG":"Who cares if you're the original or the Commander?","TWN":"什麼本體，什麼隊長！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"여기서 널 끝장내면 류드밀라는 나 하나뿐이다!","JPN":"ここで貴様にとどめを刺せばリュドミラは私ただ一人だ！","ENG":"Once I'm done with you, I will be the only Lyudmila!","TWN":"我如果在這裡殺了妳，我就是唯一的盧德米拉了！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"크윽......!","JPN":"くぅっ……！","ENG":"Ugh!","TWN":"呃……！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"안 되겠군요. 여기선 제가......","JPN":"見ていられません。ここは私が……","ENG":"Alright, that's it. I'll take it from here—","TWN":"沒辦法了，這裡就讓我……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그만두게. 자네에게 준 전술예장은 지금 작동 불능이야.","JPN":"よしておけ。君に与えた戦術礼装は今や作動不能状態だ。","ENG":"Stand down. Your new strategic uniform isn't operational right now.","TWN":"不行，妳的戰術禮裝現在還不能使用。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그리고 무리하는 건 자네 몸도 마찬가지 아닌가.","JPN":"それに君の身体とて無理が効くわけではないだろう。","ENG":"Besides, your body's also under significant duress right now.","TWN":"而且妳的身體也一樣不行了吧。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만...... 이대로 두면 류드밀라가 당할지도 모릅니다.","JPN":"しかし……このままではリュドミラがやられるかもしれません。","ENG":"But... At this rate, Lyudmila just might lose.","TWN":"但是……這樣下去盧德米拉會被殺掉的。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라를 믿게.","JPN":"彼女を信じるんだ。","ENG":"Have a little more faith in her.","TWN":"相信盧德米拉。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사람은 때론 스스로 극복해야 할 것도 있는 법이야.","JPN":"人には、自ら克服すべきことがあるものだ。","ENG":"Sometimes, folks just need to overcome things on their own.","TWN":"人有時候需要自己克服困難。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 뭐, 친구로서 등을 떠밀어 주는 것 정도는 해 줄 수 있겠지.","JPN":"ただまあ、友人として背中を押してやるくらいのことはいいかもしれんな。","ENG":"Then again, I guess she could use a little pep talk from a friend.","TWN":"不過嘛，作為朋友，稍微給她一點幫助倒是可以。"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네......?","JPN":"はい……？","ENG":"Huh?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_COLLAPSE","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"지긋지긋했던 전쟁도 이제 끝낼 시간이다.","JPN":"この忌々しい戦争についに終止符を打つ時が来た。","ENG":"It's finally time to end this tiresome war.","TWN":"這惱人的戰爭現在也該結束了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"우린 너무 오래 싸웠어. 그렇지?","JPN":"私たちはあまりにも長く戦いすぎた。そうだろう？","ENG":"We've fought for way too long. Haven't we?","TWN":"我們廝殺得太久了，對吧？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"네 대원들이라면 걱정 마라. 내 힘의 일부로 유용하게 써 줄 테니까.","JPN":"もう隊員の身を案ずる必要はないぞ。\\nじきに我が一部として取り込み、有効に活用してやるからな。","ENG":"Don't worry about your troops. I'll make great use of them as a part of me.","TWN":"不用擔心妳的隊員們，他們會成為我力量的一部分的。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"헛소리 마라! 누가 그렇게 둘 줄 알고......!","JPN":"ふざけるな！　そんなことをさせると思うか……！","ENG":"Don't you dare! I won't let you!","TWN":"閉上妳的臭嘴！我不會讓你得逞……！"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"전대장, 상황이 급박한 모양이군.","JPN":"戦隊長、だいぶ緊迫しているようだな。","ENG":"Sounds like things are getting pretty tough out there, Commander.","TWN":"隊長，看起來情況不妙呢。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런데 한 가지 물어 봐도 되겠나?","JPN":"ところで、一つだけ聞いていいか？","ENG":"But can I ask you something?","TWN":"不過妳能回答我一個問題嗎？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"관리자...... 님?","JPN":"管理者様……？","ENG":"Err... Administrator?","TWN":"管理者……大人？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"시간이 없습니다. 나중에 대답해도 되겠습니까?","JPN":"今は一刻を争います。後にしていただけますか？","ENG":"I'm afraid I don't have time for that. May I respond to you later?","TWN":"我現在沒有空，我可以之後再回答您嗎？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니, 지금 들어야겠어.","JPN":"いや、今だからこそ聞かせてほしい。","ENG":"No, I need your answer now.","TWN":"不，我現在就要問。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"건물도 거침없이 집어던지던 사람이 왜 그 힘을 사용할 생각은 안 하는 건가?","JPN":"君はビルも平気で投げ飛ばしていたはずだ。\\nなぜその力を今使わないのかね？","ENG":"You were tossing buildings like they were nothing. Why won't you tap into that power now?","TWN":"一個可以把整個大樓都能扔出去的人，為什麼不使用那個力量呢？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};